// Parse HTML from 4 sources and extract document links
const sources = [
  { name: 'thuvienphapluat', data: $('Crawl TVPL').first().json },
  { name: 'gdt', data: $('Crawl GDT').first().json },
  { name: 'chinhphu', data: $('Crawl ChinhPhu').first().json },
  { name: 'luatvietnam', data: $('Crawl LuatVN').first().json },
];

const documents = [];
const seen = new Set();

for (const src of sources) {
  const html = typeof src.data === 'string' ? src.data : (src.data.data || '');

  // Extract document links - regex patterns for Vietnamese legal documents
  const patterns = [
    /(?:Nghị định|NĐ)\s+\d+\/\d+\/NĐ-CP/gi,
    /(?:Thông tư|TT)\s+\d+\/\d+\/TT-BTC/gi,
    /(?:Luật)\s+\d+\/\d+\/QH\d+/gi,
    /(?:Nghị quyết|NQ)\s+\d+\/\d+/gi,
    /(?:Công văn|CV)\s+\d+\/\w+-\w+/gi,
  ];

  for (const pattern of patterns) {
    const matches = html.match(pattern) || [];
    for (const match of matches) {
      const normalized = match.trim();
      if (!seen.has(normalized) && normalized.match(/thuế|TNCN|BHXH|việc làm/i)) {
        seen.add(normalized);
        documents.push({
          document_name: normalized,
          source_site: src.name,
          source_url: '', // Would be extracted from href
        });
      }
    }
  }
}

return [{ json: { documents, total_found: documents.length } }];

const found = $('Parse & Merge').first().json.documents || [];
const existing = $input.all().map(i => i.json.document_name);
const existingSet = new Set(existing);

const newDocs = found.filter(d => !existingSet.has(d.document_name));

if (newDocs.length === 0) {
  return [{ json: { has_new: false, answer: 'Không có văn bản mới liên quan.', agent: 'update' } }];
}

return [{ json: { has_new: true, new_documents: newDocs, count: newDocs.length } }];

const raw = $input.first().json.text || $input.first().json.message?.content || '{}';
const newDocs = $('Filter New').first().json.new_documents || [];

let analysis;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  analysis = match ? JSON.parse(match[0]) : { summary: raw, impact_level: 'LOW' };
} catch(e) {
  analysis = { summary: raw, impact_level: 'LOW' };
}

// Prepare DB inserts
const inserts = newDocs.map(doc => ({
  document_name: doc.document_name,
  source_url: doc.source_url || '',
  source_site: doc.source_site || '',
  summary: analysis.summary,
  impact_level: analysis.impact_level,
  changes: JSON.stringify(analysis.changes || []),
  affected_files: JSON.stringify(analysis.affected_files || []),
  patch_suggestions: JSON.stringify(analysis.patch_suggestions || []),
}));

return inserts.map(i => ({ json: { ...i, analysis } }));

// Handle manual upload
const content = $json.content || '';
const filename = $json.filename || 'uploaded_doc';

return [{ json: { has_new: true, new_documents: [{ document_name: filename, content }], count: 1 } }];

const results = $input.all();
const report = {
  agent: 'update',
  total_crawled: results.length,
  new_found: results.filter(r => r.json.analysis).length,
  high_impact: results.filter(r => r.json.impact_level === 'HIGH').length,
  updates: results.map(r => ({ name: r.json.document_name, impact: r.json.impact_level, summary: r.json.summary })),
  disclaimer: 'Kết quả phân tích tự động, cần human review trước khi áp dụng.'
};
return [{ json: report }];
